double AFunction(double x) {
  return (x*x-1/2);
}

// TRUE if x1*x2 negative
int RootBracketed(double x1,double x2) {
  int result;
  if ((x1 > 0 && x2 > 0) || (x1 < 0 && x2 < 0))
    result = FALSE;
  else
    result = TRUE;
  return result;
}

